@st.cache_data(ttl=3600, show_spinner=False)
def fetch_omdb_data(imdb_id, title, year):
    result = {'poster': None, 'rt_score': 0}
    try:
        if imdb_id and str(imdb_id).startswith('tt'):
            url = f"http://www.omdbapi.com/?i={imdb_id}&apikey={OMDB_API_KEY}"
        else:
            url = f"http://www.omdbapi.com/?t={title.replace(' ', '+')}&y={year}&apikey={OMDB_API_KEY}"
        resp = requests.get(url, timeout=3)
        if resp.status_code == 200:
            data = resp.json()
            if data.get('Poster') and data['Poster'] != 'N/A':
                result['poster'] = data['Poster']
            for r in data.get('Ratings', []):
                if r['Source'] == 'Rotten Tomatoes':
                    result['rt_score'] = int(r['Value'].replace('%', ''))
    except Exception:
        pass
    return result


def _runtime_str(raw):
    try:
        m = int(float(raw))
        return f"{m // 60}h {m % 60}m" if m > 0 else ''
    except (ValueError, TypeError):
        return ''


def _clean(val):
    s = str(val).strip()
    return '' if s in ('', 'nan', 'None', 'none') else s


def _lang_display(code):
    return LANG_NAMES.get(code.lower().strip(), code)


